import subprocess
import os

def run_copilot(command, prompt, target=None, language=None):
    copilot_path = os.path.expanduser("~/.local/share/gh/copilot/copilot")

    if not os.path.exists(copilot_path):
        return {"error": "Copilot CLI not found. Run 'gh auth login' first."}

    # Build the prompt based on command
    if command == "suggest":
        full_prompt = f"{language or ''}: {prompt}" if language else prompt
        cmd = [copilot_path, "-p", full_prompt]
    elif command == "explain":
        if target and os.path.exists(target):
            with open(target, 'r') as f:
                code = f.read()
            full_prompt = f"Explain this code:\n\n{code}"
        elif target:
            full_prompt = f"Explain this code:\n\n{target}"
        else:
            full_prompt = f"Explain: {prompt}"
        cmd = [copilot_path, "-p", full_prompt]
    else:
        return {"error": f"Unknown command: {command}"}

    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            timeout=60
        )
        return {
            "stdout": result.stdout,
            "stderr": result.stderr,
            "returncode": result.returncode
        }
    except subprocess.TimeoutExpired:
        return {"error": "Command timed out after 60 seconds"}
    except Exception as e:
        return {"error": str(e)}

args = args or {}
