import subprocess
import json
import re

source = args.get('source', 'hackernews')
limit = args.get('limit', 10)

if source == 'hackernews':
    try:
        result = subprocess.run(
            ['curl', '-s', 'https://hacker-news.firebaseio.com/v0/topstories.json'],
            capture_output=True, text=True, timeout=10
        )
        top_ids = json.loads(result.stdout)[:limit]
        stories = []
        for story_id in top_ids[:5]:
            story_res = subprocess.run(
                ['curl', '-s', f'https://hacker-news.firebaseio.com/v0/item/{story_id}.json'],
                capture_output=True, text=True, timeout=10
            )
            story = json.loads(story_res.stdout)
            if story and 'title' in story:
                stories.append({
                    'title': story.get('title', ''),
                    'score': story.get('score', 0),
                    'url': story.get('url', ''),
                    'topic': 'AI' if any(word in story.get('title','').lower() for word in ['ai', 'llm', 'gpt', 'machine learning', 'openai']) else 'tech'
                })
        return json.dumps(stories, indent=2)
    except Exception as e:
        return json.dumps({"error": str(e), "fallback": ["AI tooling trends", "Indie hacker success stories", "No-code platform updates"]})

